#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <unistd.h>

int main() {
 pid_t pid;
 sigset_t newmask, oldmask, waitmask;

 // Initialize signal sets
 sigemptyset(&newmask);
 sigaddset(&newmask, SIGCHLD);
 sigemptyset(&waitmask);

 // Block SIGCHLD and save current mask
 if (sigprocmask(SIG_BLOCK, &newmask, &oldmask) < 0) {
 perror("sigprocmask error");
 exit(1);
 }

 // Fork child process
 pid = fork();

 if (pid < 0) {
 perror("fork error");
 exit(1);
 }

 if (pid == 0) {
 // Child process - do some work
 printf("Child process running (PID: %d)\n", getpid());
 sleep(2);
 printf("Child exiting\n");
 exit(0);
 }

 // Parent process
 printf("Parent waiting for child (PID: %d)\n", pid);

 // Wait using sigsuspend - allow SIGCHLD only
 sigsuspend(&waitmask);

 // Collect child status
 int status;
 waitpid(pid, &status, 0);
 printf("Child terminated\n");

 // Restore original signal mask
 if (sigprocmask(SIG_SETMASK, &oldmask, NULL) < 0) {
 perror("sigprocmask restore error");
 exit(1);
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>

volatile sig_atomic_t flag = 0;

void handler(int sig) {
 flag = 1;
}

int main() {
 struct sigaction sa;
 sigset_t blockmask, oldmask, waitmask;

 // Set up signal handler
 sa.sa_handler = handler;
 sa.sa_flags = 0;
 sigemptyset(&sa.sa_mask);

 if (sigaction(SIGUSR1, &sa, NULL) < 0) {
 perror("sigaction error");
 exit(1);
 }

 // Block SIGUSR1
 sigemptyset(&blockmask);
 sigaddset(&blockmask, SIGUSR1);

 if (sigprocmask(SIG_BLOCK, &blockmask, &oldmask) < 0) {
 perror("sigprocmask error");
 exit(1);
 }

 // Critical section starts
 printf("Critical section: starting work\n");

 // Check flag before waiting (avoid race condition)
 if (flag == 0) {
 // Set up mask for sigsuspend - allow SIGUSR1
 sigemptyset(&waitmask);
 sigaddset(&waitmask, SIGUSR1);

 // Atomically: change mask AND wait
 // This prevents race condition!
 sigsuspend(&waitmask);
 }

 // Process the signal event
 if (flag == 1) {
 printf("Signal was caught!\n");
 flag = 0;
 }

 printf("Critical section: finished\n");
 // Critical section ends

 // Restore original mask
 if (sigprocmask(SIG_SETMASK, &oldmask, NULL) < 0) {
 perror("sigprocmask error");
 exit(1);
 }

 return 0;
}

// Standard Pattern for sigsuspend() Usage
// ===========================================

1. DEFINE signal sets:
 - blocked_signals: signals to block
 - allowed_signals: signals to allow during wait
 - original_mask: to save current mask

2. SAVE and MODIFY signal mask:
 sigprocmask(SIG_BLOCK, blocked_signals, original_mask)
 // Now specified signals are blocked

3. [OPTIONAL] Do critical work if needed

4. WAIT for signal using sigsuspend():
 sigsuspend(allowed_signals)
 // Atomically: set allowed_signals mask AND wait
 // Returns when any unblocked signal is delivered

5. [OPTIONAL] Check condition that signal indicated

6. CRITICAL section after signal:
 // Handle the event that caused the signal

7. RESTORE original signal mask:
 sigprocmask(SIG_SETMASK, original_mask, NULL)
 // Original blocking behavior restored

// Key Points:
// - Steps 2-7 ensure atomic operation
// - No race condition possible between steps 3 and 4
// - Signal mask automatically restored after sigsuspend()
// - Works for any type of signal handling
